#!/usr/bin/env node
/**
 * VEXTREME — lib/build-arc-bundles.js
 *
 * Arc-chunked language bundles — the od-001/td-006 pilot. Assembles one
 * data/strings/compiled/arcs/{arcId}.{lang}.json per language, for every arc
 * that opts in via `bundlingStrategy: "arc-chunked"` in data/arcs-v2.json.
 * Each bundle merges every scope every member slug uses (+ common), for a
 * given language, into one file — the same data widgets/fab-lang.js's
 * per-scope fan-out would otherwise need N parallel requests to assemble at
 * runtime, now merged once at build time.
 *
 * This is additive and scoped: arcs that do not declare bundlingStrategy are
 * completely unaffected — they keep working exactly as before, through the
 * existing per-scope path. Only opted-in arcs get a bundle here; today that
 * is "victor_dossier" alone (see docs/architecture/06-i18n.md, "Arc-chunked
 * bundling pilot").
 *
 * Run manually:   node lib/build-arc-bundles.js
 * Auto-run via:   after lib/strings-compile.js, before lib/build-vextreme.js
 *                 (needs strings-compile.js's scope bundles as input)
 *
 * Pure functions exported for testing:
 *   arcChunkedArcs(arcsDef) → [arcId]
 *   memberSlugs(arcDef) → [slug]
 *   scopesForSlugs(slugs, viewmodels) → [scope] (deduped, 'common' always included)
 *   mergeScopeBundlesForLang(scopes, category, lang, scopesDir) → object
 *
 * LATTICE:BEGIN — generated by lib/build-lattice-headers.js from docs/lattice-map.json. Do not hand-edit; edit the JSON and regenerate.
 *   role      : arc-chunked language bundle assembler — the od-001/td-006 pilot, opt-in per arc
 *   reads     : data/arcs-v2.json (bundlingStrategy per arc)
 *               data/nodes.json (arc section slugs, via data/arcs-v2.json)
 *               data/viewmodels.json (per-slug scope overrides)
 *               data/strings/compiled/scopes/{category}/{scope}.{lang}.json (lib/strings-compile.js's output)
 *               lib/vex-config.js
 *   writes    : data/strings/compiled/arcs/{arcId}.{lang}.json (one per opted-in arc per language present)
 *               data/strings/compiled/arcs/index.json (which arcs are chunked, their langs, key counts)
 *   loaded-by : manual run: node lib/build-arc-bundles.js
 *               .github/workflows/build-index.yml (after strings-compile.js, before build-vextreme.js)
 *               tests/26-build-arc-bundles.test.js
 *   tested-by : tests/26-build-arc-bundles.test.js
 *
 *   CHANGE MAP — if you touch X here, also check:
 *     a second arc opts into bundlingStrategy: "arc-chunked":
 *       - nothing code-side — this script already generalizes; only the pilot's scope is one arc, not the mechanism
 *     data/strings/compiled/arcs/{arcId}.{lang}.json path or shape changed:
 *       - widgets/fab-lang.js (fetches this exact path when window.VEX_STRING_ARC_BUNDLE is set)
 *       - lib/build-vextreme.js (emits window.VEX_STRING_ARC_BUNDLE)
 *       - lib/build-sw.js (precaches this exact path for opted-in arcs)
 * LATTICE:END
 */

'use strict';

const fs   = require('fs');
const path = require('path');
const { scopeRelPath, DEFAULT_CATEGORY, Scope } = require('./vex-config');

const ROOT         = path.join(__dirname, '..');
const ARCS_PATH     = path.join(ROOT, 'data', 'arcs-v2.json');
const NODES_PATH     = path.join(ROOT, 'data', 'nodes.json');
const VMS_PATH       = path.join(ROOT, 'data', 'viewmodels.json');
const SCOPES_DIR     = path.join(ROOT, 'data', 'strings', 'compiled', 'scopes');
const ARCS_OUT_DIR   = path.join(ROOT, 'data', 'strings', 'compiled', 'arcs');

// ── Pure computation ─────────────────────────────────────────────────────────

// arcChunkedArcs — which arc IDs opted into arc-chunked bundling.
function arcChunkedArcs(arcsDef) {
  return Object.entries(arcsDef)
    .filter(([id, def]) => !id.startsWith('_') && def && def.bundlingStrategy === 'arc-chunked')
    .map(([id]) => id);
}

// memberSlugs — every slug named across an arc's sections, in section order,
// deduped. Mirrors the 'explicit' half of lib/build-index.js's buildArcMap —
// this script does not need chronological-section resolution because an
// arc-chunked arc's membership is what needs bundling, not display order.
function memberSlugs(arcDef) {
  const seen = new Set();
  const slugs = [];
  for (const section of arcDef.sections || []) {
    for (const slug of section.slugs || []) {
      if (seen.has(slug)) continue;
      seen.add(slug);
      slugs.push(slug);
    }
  }
  return slugs;
}

// scopesForSlugs — the union of scopes every member slug would fetch, using
// the same default lib/build-index.js's buildViewmodel applies (a viewmodels
// override, else `pages.{slug}`), always including 'common'.
function scopesForSlugs(slugs, viewmodels) {
  const scopes = new Set([Scope.COMMON]);
  for (const slug of slugs) {
    const override = (viewmodels || {})[slug];
    const slugScopes = (override && override.scopes) || [`pages.${slug}`];
    for (const scope of slugScopes) scopes.add(scope);
  }
  return [...scopes];
}

// mergeScopeBundlesForLang — reads every scope's compiled bundle for one
// language and merges into one flat map. Missing bundles for this lang are
// skipped silently (a scope may simply not have that language yet) — the
// per-scope path already handles this same gap the same way.
function mergeScopeBundlesForLang(scopes, category, lang, scopesDir) {
  const merged = {};
  for (const scope of scopes) {
    const relPath  = scopeRelPath(scope, category);
    const filePath = path.join(scopesDir, relPath + '.' + lang + '.json');
    if (!fs.existsSync(filePath)) continue;
    const data = JSON.parse(fs.readFileSync(filePath, 'utf8'));
    Object.assign(merged, data);
  }
  return merged;
}

// langsPresent — every language that has at least one compiled bundle among
// the given scopes, scanning scopes/{category}/{...}.{lang}.json filenames.
function langsPresent(scopes, category, scopesDir) {
  const langs = new Set();
  for (const scope of scopes) {
    const relPath = scopeRelPath(scope, category);
    const dir     = path.join(scopesDir, path.dirname(relPath));
    const base    = path.basename(relPath);
    if (!fs.existsSync(dir)) continue;
    for (const f of fs.readdirSync(dir)) {
      const m = f.match(new RegExp('^' + base.replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + '\\.([a-z]{2,})\\.json$'));
      if (m) langs.add(m[1]);
    }
  }
  return [...langs].sort();
}

// ── I/O — only runs when executed directly ────────────────────────────────────

if (require.main === module) {
  const arcsDef    = JSON.parse(fs.readFileSync(ARCS_PATH, 'utf8'));
  const nodes      = JSON.parse(fs.readFileSync(NODES_PATH, 'utf8'));
  const viewmodels = fs.existsSync(VMS_PATH) ? JSON.parse(fs.readFileSync(VMS_PATH, 'utf8')) : {};

  const chunkedArcs = arcChunkedArcs(arcsDef);
  const arcsIndex   = {};

  if (chunkedArcs.length) fs.mkdirSync(ARCS_OUT_DIR, { recursive: true });

  for (const arcId of chunkedArcs) {
    const slugs    = memberSlugs(arcsDef[arcId]);
    const scopes   = scopesForSlugs(slugs, viewmodels);
    // category: production is the default for real content; every member slug
    // in the pilot arc shares it today. A future multi-category arc would need
    // per-slug category tracking — out of scope for a one-arc pilot.
    const category = DEFAULT_CATEGORY;
    const langs    = langsPresent(scopes, category, SCOPES_DIR);

    arcsIndex[arcId] = { slugs, scopes, category, langs: {} };

    for (const lang of langs) {
      const bundle  = mergeScopeBundlesForLang(scopes, category, lang, SCOPES_DIR);
      const outPath = path.join(ARCS_OUT_DIR, `${arcId}.${lang}.json`);
      fs.writeFileSync(outPath, JSON.stringify(bundle, null, 2) + '\n');
      arcsIndex[arcId].langs[lang] = Object.keys(bundle).length;
      console.log(`[build-arc-bundles] Wrote ${outPath} (${Object.keys(bundle).length} keys)`);
    }
  }

  if (chunkedArcs.length) {
    fs.writeFileSync(path.join(ARCS_OUT_DIR, 'index.json'), JSON.stringify(arcsIndex, null, 2) + '\n');
  }

  console.log(`[build-arc-bundles] Done. ${chunkedArcs.length} arc-chunked arc(s): ${chunkedArcs.join(', ') || '(none)'}`);
}

module.exports = { arcChunkedArcs, memberSlugs, scopesForSlugs, mergeScopeBundlesForLang, langsPresent };

// [VXG RealForever]
